import{_ as t,o,c as a,a2 as r}from"./chunks/framework.Crpw6aS5.js";const n=JSON.parse('{"title":"1957年 · 熊市起步","description":"","frontmatter":{},"headers":[],"relativePath":"05_quotes/by-year/1957年.md","filePath":"05_quotes/by-year/1957年.md"}'),u={name:"05_quotes/by-year/1957年.md"};function l(q,e,c,s,_,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="_1957年-·-熊市起步" tabindex="-1">1957年 · 熊市起步 <a class="header-anchor" href="#_1957年-·-熊市起步" aria-label="Permalink to &quot;1957年 · 熊市起步&quot;">​</a></h1><blockquote><p>&quot;在市场下跌时，我反而看到了更多的投资机会。价值不会因为价格下跌而改变。&quot;——巴菲特（26岁）</p></blockquote><p>本页收录1957年巴菲特合伙基金的经典语录，这是他26岁时的第一封致合伙人信。</p><hr><h2 id="核心金句" tabindex="-1">核心金句 <a class="header-anchor" href="#核心金句" aria-label="Permalink to &quot;核心金句&quot;">​</a></h2><blockquote><p>&quot;我只参与我理解并能判断其价值的投资机会。那些我不理解的机会，无论看起来多有吸引力，我都不参与。&quot;</p></blockquote><blockquote><p>&quot;我不会试图预测市场走势。我关注的是个别企业的价值。当市场整体下跌时，那些真正有价值的企业也会被错杀——这正是机会显现的时刻。&quot;</p></blockquote><blockquote><p>&quot;在市场下跌时，我反而看到了更多的投资机会。价值不会因为价格下跌而改变，改变的只是人心。&quot;</p></blockquote><blockquote><p>&quot;我希望我的合伙人在所有市场环境下都能保持理性，不要被短期波动所左右。短期的市场表现，从来不是衡量投资能力的真正标准。&quot;</p></blockquote><blockquote><p>&quot;我的目标是跑赢道琼斯指数。在熊市时领先指数越多，在牛市时落后得越少。长期而言，这是最可靠的积累财富的方式。&quot;</p></blockquote><hr><h2 id="本年背景" tabindex="-1">本年背景 <a class="header-anchor" href="#本年背景" aria-label="Permalink to &quot;本年背景&quot;">​</a></h2><p>1957年，美国道琼斯指数从1956年末的499点跌至435点，全年下跌约12%。这是巴菲特1956年创立合伙基金后的第一个完整年度。26岁的他，在合伙信中写下了最朴素也最深刻的原则：不懂不买、不预测市场、跑赢指数。这些原则在此后60年里从未改变。</p><hr><h2 id="深入阅读" tabindex="-1">深入阅读 <a class="header-anchor" href="#深入阅读" aria-label="Permalink to &quot;深入阅读&quot;">​</a></h2><p><a href="/01_letters/1957年/翻译.html">01_letters/1957年/翻译</a> · <a href="/05_quotes/by-year/1956年.html">05_quotes/by-year/1956年</a></p>',16)])])}const i=t(u,[["render",l]]);export{n as __pageData,i as default};
